{
  "title": "सबस्ट्रिंग निष्कर्षण",
  "group": "स्ट्रिंग हेरफेर",
  "options": [
    {
      "text": "बुरा बिल्ली"
    },
    {
      "text": "बुरा बिल्ली, अच्छा बिल्ली:9"
    },
    {
      "text": "अच्छा बिल्ली"
    },
    {
      "text": "त्रुटि"
    }
  ],
  "questionProse": [
    "इस स्क्रिप्ट में `:` क्या करता है?"
  ],
  "explanationProse": [
    "`${var:offset}` सिंटैक्स `offset` से शुरू होने वाली सबस्ट्रिंग निकालता है। यहाँ, आउटपुट है:",
    "विशिष्ट लंबाई की सबस्ट्रिंग निकालने के लिए, `${var:offset:length}` का उपयोग करें।\n\n    स्ट्रिंग के अंत से निकालने के लिए, `${var: -offset}` का उपयोग करें। (ध्यान दें `-` से पहले स्पेस!)"
  ]
}
